-- ----------------------------------------------------------------------------
-- vw_employees: Table: Employees — people who submit expense reports or review them.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_employees WITH (security_invoker = ON) AS
SELECT
  t.employee_id,
  calc_employees_name(t.employee_id) AS name,                                   -- Display name (FirstName + LastName).
  t.first_name,
  t.last_name,
  t.email_address,                                                              -- Used as the click-to-login identity.
  t.role,                                                                       -- employee | manager | finance
  t.budget_limit                                                                -- Per-report ceiling above which reports are flagged over-budget. Applies to submitters; reviewers (manager/finance) can be left null.
FROM employees t;

-- ----------------------------------------------------------------------------
-- vw_expense_reports: Table: ExpenseReports — one submission, containing many line items.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_expense_reports WITH (security_invoker = ON) AS
SELECT
  t.expense_report_id,
  t.name,                                                                       -- Short title of the report.
  t.employee,                                                                   -- Submitter.
  calc_expense_reports_employee_name(t.expense_report_id) AS employee_name,
  calc_expense_reports_employee_budget_limit(t.expense_report_id) AS employee_budget_limit,
  t.approval_status,                                                            -- pending | approved | rejected
  calc_expense_reports_total_amount(t.expense_report_id) AS total_amount,       -- Sum of all line-item amounts on this report.
  calc_expense_reports_is_over_budget(t.expense_report_id) AS is_over_budget,   -- True when TotalAmount exceeds the employee's BudgetLimit.
  calc_expense_reports_is_approved(t.expense_report_id) AS is_approved,         -- True iff ApprovalStatus is 'approved'.
  calc_expense_reports_requires_escalation(t.expense_report_id) AS requires_escalation-- Over-budget AND not yet approved — manager's escalation queue.
FROM expense_reports t;

-- ----------------------------------------------------------------------------
-- vw_expense_items: Table: ExpenseItems — individual line items on a report.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_expense_items WITH (security_invoker = ON) AS
SELECT
  t.expense_item_id,
  t.name,                                                                       -- Short description of the expense.
  t.expense_report,                                                             -- Parent report.
  t.amount                                                                      -- Dollar amount of this line item.
FROM expense_items t;

